#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-06-23

# Tests the deterministic half of the audit-activation skill —
# src/skills/audit-activation/scripts/run-activation-audit.sh — across
# real data, empty telemetry, missing file, malformed JSONL, and --json mode.
# The model-driven classification half is covered by the eval YAML.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
AUDIT="$REPO_ROOT/src/skills/audit-activation/scripts/run-activation-audit.sh"

RED=$'\033[0;31m'; GREEN=$'\033[0;32m'; NC=$'\033[0m'
PASS=0; FAIL=0
pass() { echo "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
fail() { echo "  ${RED}✗${NC} $1"; FAIL=$((FAIL + 1)); }

echo "════════════════════════════════════════════════════════════════"
echo "  audit-activation script (run-activation-audit.sh)"
echo "════════════════════════════════════════════════════════════════"

# Sandbox tree: a fake src/agents + .claude/logs so the script's path-join
# resolves to controlled fixtures (it derives REPO_ROOT from its own location,
# so we copy the script into a temp tree four levels deep to match).
SBX="$(mktemp -d)"
mkdir -p "$SBX/src/skills/audit-activation/scripts" "$SBX/src/agents" "$SBX/.claude/logs" "$SBX/src/skills/demo"
cp "$AUDIT" "$SBX/src/skills/audit-activation/scripts/run-activation-audit.sh"
for a in alpha-agent beta-agent gamma-agent; do printf 'name: %s\n' "$a" > "$SBX/src/agents/$a.md"; done
printf 'README\n' > "$SBX/src/agents/README.md"   # must be excluded
# a skill that references alpha-agent (so its skill-ref count > 0)
printf 'subagent_type="ork:alpha-agent"\n' > "$SBX/src/skills/demo/SKILL.md"
RUN="$SBX/src/skills/audit-activation/scripts/run-activation-audit.sh"

# ── 1. healthy telemetry: alpha fires, beta/gamma dormant ───────────────────
{
  echo '{"timestamp":"2026-06-01T00:00:00Z","subagent_type":"ork:alpha-agent"}'
  echo '{"timestamp":"2026-06-02T00:00:00Z","subagent_type":"alpha-agent"}'
  echo '{"timestamp":"2026-06-03T00:00:00Z","subagent_type":"Explore"}'
  echo '{"timestamp":"2026-06-04T00:00:00Z","subagent_type":"candlekeep:reader"}'
} > "$SBX/.claude/logs/subagent-spawns.jsonl"

out="$(bash "$RUN" 2>&1)"
echo "$out" | grep -q "fired: 1/3"        && pass "fired count (1 of 3 agents)"          || fail "fired count — got: $(echo "$out" | grep -i fired)"
echo "$out" | grep -q "README"            && fail "README leaked into inventory"          || pass "README excluded from inventory"
echo "$out" | grep -qE "beta-agent.*DEAD" && pass "beta-agent (0 refs) → DEAD candidate"  || fail "beta-agent not flagged DEAD"
echo "$out" | grep -qE "alpha-agent"      && pass "alpha-agent shown in fired"            || fail "alpha-agent missing"
echo "$out" | grep -q "ork catalog"       && pass "renders spawn split"                   || fail "no spawn split"

# ── 2. --json mode is valid JSON with required keys ─────────────────────────
json="$(bash "$RUN" --json 2>&1)"
if echo "$json" | node -e 'let s="";process.stdin.on("data",d=>s+=d).on("end",()=>{const j=JSON.parse(s);if(j.totals&&Array.isArray(j.agents)&&"conc_top5_pct"in j)process.exit(0);process.exit(1)})' 2>/dev/null; then  # silent: best-effort — node exit code IS the assertion; parse-error text is noise
  pass "--json emits valid JSON with totals/agents/conc keys"
else
  fail "--json invalid or missing keys"
fi

# ── 3. empty telemetry → no crash, 0 fired ──────────────────────────────────
: > "$SBX/.claude/logs/subagent-spawns.jsonl"
out="$(bash "$RUN" 2>&1)" && pass "empty telemetry: exit 0" || fail "empty telemetry crashed"
echo "$out" | grep -q "fired: 0/3" && pass "empty telemetry: 0/3 fired" || fail "empty telemetry wrong count"

# ── 4. missing telemetry file → graceful (0 fired, no crash) ────────────────
rm -f "$SBX/.claude/logs/subagent-spawns.jsonl"
bash "$RUN" >/dev/null 2>&1 && pass "missing telemetry: exit 0 (graceful)" || fail "missing telemetry crashed"

# ── 5. malformed JSONL lines are skipped, valid ones still counted ──────────
{
  echo 'NOT JSON AT ALL'
  echo '{"timestamp":"2026-06-05T00:00:00Z","subagent_type":"ork:alpha-agent"}'
  echo '{partial'
} > "$SBX/.claude/logs/subagent-spawns.jsonl"
out="$(bash "$RUN" 2>&1)" && pass "malformed JSONL: exit 0" || fail "malformed JSONL crashed"
echo "$out" | grep -q "fired: 1/3" && pass "malformed JSONL: valid line still counted" || fail "malformed JSONL miscounted"

# ── 6. --help works and exits 0 ─────────────────────────────────────────────
bash "$RUN" --help >/dev/null 2>&1 && pass "--help exits 0" || fail "--help failed"
# ── 7. unknown flag rejected (non-zero) ─────────────────────────────────────
if bash "$RUN" --bogus >/dev/null 2>&1; then fail "unknown flag not rejected"; else pass "unknown flag rejected (non-zero)"; fi

rm -rf "$SBX"
echo "════════════════════════════════════════════════════════════════"
echo "  Total: $((PASS + FAIL))  |  Passed: ${GREEN}${PASS}${NC}  |  Failed: ${RED}${FAIL}${NC}"
echo "════════════════════════════════════════════════════════════════"
[ "$FAIL" -eq 0 ]
